import{_ as e,o,c as a,S as r}from"./chunks/framework.DZlzLDBr.js";const g=JSON.parse('{"title":"Grading","description":"","frontmatter":{},"headers":[],"relativePath":"Grading.md","filePath":"Grading.md","lastUpdated":null}'),d={name:"Grading.md"};function n(s,t,i,c,l,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="how-grading-works" tabindex="-1">How grading works <a class="header-anchor" href="#how-grading-works" aria-label="Permalink to &quot;How grading works&quot;">​</a></h2><p>After you reveal a card, you grade recall quality. That grade is passed to FSRS, which updates difficulty and next review timing.</p><h2 id="grading-modes" tabindex="-1">Grading modes <a class="header-anchor" href="#grading-modes" aria-label="Permalink to &quot;Grading modes&quot;">​</a></h2><p>Sprout offers two grading modes, configurable in <strong>Settings → Study → Grading buttons</strong>:</p><h3 id="two-button-mode-default-recommended" tabindex="-1">Two-button mode (default, recommended) <a class="header-anchor" href="#two-button-mode-default-recommended" aria-label="Permalink to &quot;Two-button mode (default, recommended)&quot;">​</a></h3><p>Two-button mode works as a simple pass / fail system:</p><table tabindex="0"><thead><tr><th>Button</th><th>Shortcut</th><th>When to use</th></tr></thead><tbody><tr><td>Again (Fail)</td><td><code>1</code></td><td>Your answer is incorrect, or you couldn&#39;t recall it. If your answer is only partially correct, be strict with yourself — if it would count as wrong in a real-life context, press Again.</td></tr><tr><td>Good (Pass)</td><td><code>2</code></td><td>Your answer is correct.</td></tr></tbody></table><p>This mode is simpler and faster, and is recommended for most users.</p><h3 id="four-button-mode" tabindex="-1">Four-button mode <a class="header-anchor" href="#four-button-mode" aria-label="Permalink to &quot;Four-button mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Shortcut</th><th>When to use</th></tr></thead><tbody><tr><td>Again</td><td><code>1</code></td><td>Your answer is incorrect or you couldn&#39;t recall it. If your answer is partially correct, be strict with yourself — if it would count as a fail in a real-life context, press Again. You&#39;ll typically use this button about 5–20% of the time.</td></tr><tr><td>Hard</td><td><code>2</code></td><td>Your answer is correct, but you had doubts about it or it took a long time to recall.</td></tr><tr><td>Good</td><td><code>3</code></td><td>Your answer is correct, but it took some mental effort to recall. When used properly, this should be the most commonly used button — roughly 80–95% of the time.</td></tr><tr><td>Easy</td><td><code>4</code></td><td>Your answer is correct and it took no mental effort to recall.</td></tr></tbody></table><p>This mode gives finer control, but it is slower and easier to overthink.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use four buttons only if you want extra grading granularity. Otherwise, keep two-button mode.</p></div><h2 id="auto-graded-card-types" tabindex="-1">Auto-graded card types <a class="header-anchor" href="#auto-graded-card-types" aria-label="Permalink to &quot;Auto-graded card types&quot;">​</a></h2><p>Some card types are graded automatically based on your interaction — you don&#39;t press a separate grade button:</p><table tabindex="0"><thead><tr><th>Card type</th><th>How it&#39;s graded</th></tr></thead><tbody><tr><td><strong>Multiple Choice</strong></td><td>Correct option → Good. Incorrect → Again.</td></tr><tr><td><strong>Ordered Questions</strong></td><td>Correct sequence → Good. Any item wrong → Again.</td></tr></tbody></table><p>For these types, your response applies the grade directly.</p><h2 id="how-grading-affects-scheduling" tabindex="-1">How grading affects scheduling <a class="header-anchor" href="#how-grading-affects-scheduling" aria-label="Permalink to &quot;How grading affects scheduling&quot;">​</a></h2><p>Each grade feeds into the FSRS algorithm, which updates three values for the card:</p><table tabindex="0"><thead><tr><th>Value</th><th>Updated how</th></tr></thead><tbody><tr><td><strong>Stability</strong></td><td>Increases with Good/Easy grades, decreases with Again</td></tr><tr><td><strong>Difficulty</strong></td><td>Increases when you press Again, decreases with Easy</td></tr><tr><td><strong>Next interval</strong></td><td>Calculated so your recall probability equals your target retention on the due date</td></tr></tbody></table><p>See <a href="./Scheduling">Scheduling</a> for a deeper explanation of FSRS.</p><h2 id="keyboard-shortcuts-summary" tabindex="-1">Keyboard shortcuts summary <a class="header-anchor" href="#keyboard-shortcuts-summary" aria-label="Permalink to &quot;Keyboard shortcuts summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Space</code> / <code>Enter</code></td><td>Reveal answer</td></tr><tr><td><code>1</code> – <code>2</code> (two-button)</td><td>Again / Good</td></tr><tr><td><code>1</code> – <code>4</code> (four-button)</td><td>Again / Hard / Good / Easy</td></tr></tbody></table>',24)])])}const b=e(d,[["render",n]]);export{g as __pageData,b as default};
